mapper.sql:
SELECT A.REQUEST_KEY , A.CNTPNT_SHOP_ID , FN_GET_ORGNM(A.CNTPNT_SHOP_ID) AS AGENT_NAME , A.REQ_BUY_TYPE , FN_GET_CODENM('RCP9004', A.REQ_BUY_TYPE) AS REQ_BUY_NM , A.OPER_TYPE , FN_GET_CODENM('RCP9001', A.OPER_TYPE) AS OPER_NAME , A.SERVICE_TYPE , FN_GET_CODENM('RCP0013', A.SERVICE_TYPE) AS SERVICE_NAME , A.ON_OFF_TYPE , FN_GET_CODENM('RCP0007', NVL(A.ON_OFF_TYPE, '0')) ON_OFF_NM , A.OPEN_MARKET_REFERER , MDL.MNFCT_ID , DECODE(A.REQ_BUY_TYPE, 'MM', ( SELECT MNFCT_NM FROM ORG_MNFCT_MST WHERE MNFCT_ID = MDL.MNFCT_ID ), '') AS MNFCT_NM , ( SELECT MNFCT_NM FROM ORG_MNFCT_MST WHERE MNFCT_ID = USIM.MNFCT_ID ) AS USIM_MNFCT_NM , A.REQ_USIM_SN AS OLD_USIM_SN , A.SPC_CODE , C.SOC_CODE , FN_GET_RATENM(C.SOC_CODE) AS SOC_NAME , A.CSTMR_TYPE , B.CSTMR_NATIVE_RRN , B.CSTMR_FOREIGNER_RRN , B.CSTMR_PRIVATE_CNAME , B.CSTMR_PRIVATE_NUMBER , B.CSTMR_JURIDICAL_CNAME , B.CSTMR_JURIDICAL_RRN , B.CSTMR_TEL_FN , B.CSTMR_TEL_MN , B.CSTMR_TEL_RN , B.CSTMR_TEL_FN || B.CSTMR_TEL_MN || B.CSTMR_TEL_RN AS CSTMR_TEL , B.CSTMR_MOBILE_FN , B.CSTMR_MOBILE_MN , B.CSTMR_MOBILE_RN , B.CSTMR_MOBILE_FN || B.CSTMR_MOBILE_MN || B.CSTMR_MOBILE_RN AS CSTMR_MOBILE , B.CSTMR_POST , B.CSTMR_ADDR , B.CSTMR_ADDR_DTL , B.CSTMR_MAIL , TO_CHAR(A.SYS_RDATE, 'YYYYMMDDHH24MISS') AS SYS_RDATE , A.RVISN_ID AS RVISN_ID , FN_GET_USRNM(A.RVISN_ID) AS RVISN_NM , TO_CHAR(A.RVISN_DTTM, 'YYYY-MM-DD HH24:MI:SS') AS RVISN_DTTM , A.PROD_NM AS DRCT_MNGM_PRDC_NM /* 직영상품명 */ , A.RES_NO /* 예약번호 */ , TO_CHAR(A.REQ_IN_DAY, 'YYYYMMDD') REQ_IN_DT /* 신청일자 */ , B.CSTMR_NAME /* 고객명 */ , B.CSTMR_NAME AS CSTMR_NAME2 , C.SESPLS_PROD_ID /* 단말ID */ , MDL.PRDT_CODE AS PRDT_CODE /* 단말코드 */ , MDL.PRDT_NM AS MODEL_NAME /* 단말명 */ , NVL(FN_GET_CODENM ('CMN0044', MDL.PRDT_COLR_CD), A.REQ_MODEL_COLOR) AS REQ_MODEL_COLOR /* 단말색상 */ , A.REQ_PHONE_SN /* 단말일련번호 */ , C.HNDSET_SALE_PRICE /* 출고가 */ , NVL(C.CARD_TOT_DC_AMT,0) AS CARD_DC_AMT /* 즉시할인 */ , NVL(C.USE_POINT,0) AS USE_POINT /* 포인트 */ , TO_NUMBER(C.HNDSET_SALE_PRICE) - TO_NUMBER(NVL(C.CARD_TOT_DC_AMT,0)) - TO_NUMBER(NVL(C.USE_POINT,0)) AS TOT_AMT /* 결제금액 */ , A.MEMO AS REQUEST_MEMO /* 메모 */ , APD.REQUEST_STATE_CODE AS PHONE_STATE_CODE /* 단말진행상태 */ , FN_GET_CODENM('RCP0006', APD.REQUEST_STATE_CODE) PHONE_STATE_NAME /* 단말진행상태명 */ , USIM.PRDT_NM AS USIM_NAME /* 유심모델 */ , USIM.PRDT_CODE AS USIM_ID /* 유심제품명 */ , A.REQ_USIM_SN /* 유심번호 */ , FN_GET_CODENM('RCP2035', A.USIM_KINDS_CD) AS USIM_KINDS_NM , A.REQUEST_STATE_CODE AS USIM_STATE_CODE /* 유심진행상태 */ , FN_GET_CODENM('RCP0006', A.REQUEST_STATE_CODE) AS USIM_STATE_NAME /* 유심진행상태명 */ , D.DLVRY_NAME /* 배송받는분 */ , D.DLVRY_TEL_FN , D.DLVRY_TEL_MN , D.DLVRY_TEL_RN , D.DLVRY_MOBILE_FN , D.DLVRY_MOBILE_MN , D.DLVRY_MOBILE_RN , D.DLVRY_MOBILE_FN || D.DLVRY_MOBILE_MN || D.DLVRY_MOBILE_RN AS DLVRY_MOBILE_NO , D.DLVRY_POST /* 우편번호 */ , D.DLVRY_ADDR /* 주소 */ , D.DLVRY_ADDR_DTL /* 상세주소 */ , D.DLVRY_MEMO /* 요청사항 */ , E.TB_CD /* 유심택배사 */ , (SELECT DTL_CD_NM FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'PERCEL' AND DTL_CD = E.TB_CD) AS TB_NM /* 유심택배사명 */ , E.DLVRY_NO /* 유심택배사 송장번호 */ , APD.TB_CD AS PHONE_TB_CD /* 단말택배사 */ , (SELECT DTL_CD_NM FROM NMCP_CD_DTL@DL_MCP WHERE CD_GROUP_ID = 'PERCEL' AND DTL_CD = APD.TB_CD) AS PHONE_TB_NM /* 단말택배사명 */ , APD.DLVRY_NO AS PHONE_DLVRY_NO /* 단말택배사 송장번호 */ , A.PSTATE /* 신청서상태 */ , FN_GET_CODENM('RCP0005', A.PSTATE) PSTATE_NAME /* 신청서상태명 */ FROM MCP_REQUEST@DL_MCP A , MCP_REQUEST_CSTMR@DL_MCP B , MCP_REQUEST_SALEINFO@DL_MCP C , MCP_REQUEST_DLVRY@DL_MCP D , MCP_REQUEST_STATE@DL_MCP E , CMN_INTM_MDL MDL , CMN_INTM_MDL USIM , NMCP_REQUEST_APD_STATE@DL_MCP APD /* 단말진행상태 */ WHERE 1 = 1 AND A.REQUEST_KEY = B.REQUEST_KEY AND A.REQUEST_KEY = C.REQUEST_KEY AND A.REQUEST_KEY = D.REQUEST_KEY AND A.REQUEST_KEY = E.REQUEST_KEY AND C.SESPLS_PROD_ID = MDL.PRDT_ID(+) AND A.REQ_USIM_NAME = USIM.PRDT_CODE(+) AND A.REQUEST_KEY = APD.REQUEST_KEY AND A.PROD_TYPE = '04' AND A.REQ_IN_DAY BETWEEN TO_DATE(#{strtDt} || '000000', 'YYYYMMDDHH24MISS') AND TO_DATE(#{endDt} || '235959', 'YYYYMMDDHH24MISS')
AND B.CSTMR_NAME LIKE #{searchVal} || '%'
AND A.CONTRACT_NUM = #{searchVal}
AND NVL(B.CSTMR_MOBILE_FN || B.CSTMR_MOBILE_MN || B.CSTMR_TEL_RN, B.CSTMR_TEL_FN || B.CSTMR_TEL_MN || B.CSTMR_MOBILE_RN) LIKE TRANSLATE(#{searchVal},'1234567890-','1234567890')||'%'
AND A.REQ_PHONE_SN LIKE '%' || #{searchVal} || '%'
AND A.RES_NO LIKE '%' || #{searchVal} || '%'
AND APD.REQUEST_STATE_CODE = #{paramPhoneStateCode}
AND A.REQUEST_STATE_CODE = #{paramUsimStateCode}
AND A.PSTATE = #{paramPstate}
ORDER BY A.REQUEST_KEY DESC

mapper.update:
/* rcpSelfSuffMapper.updateMcpReq */
UPDATE	MCP_REQUEST@DL_MCP
SET		REQUEST_STATE_CODE = #{usimStateCode}

		, PSTATE = #{pstate}

		, REQ_PHONE_SN = #{reqPhoneSn}
		, REQ_USIM_SN = #{reqUsimSn}
		, RVISN_ID = #{SESSION_USER_ID}
		, RVISN_DTTM = SYSDATE 
WHERE 	REQUEST_KEY = #{requestKey}

/* rcpSelfSuffMapper.updateMcpApdReq */
UPDATE	NMCP_REQUEST_APD@DL_MCP
SET		REQUEST_STATE_CODE = #{usimStateCode}

		, PSTATE = #{pstate}

		, REQ_PHONE_SN = #{reqPhoneSn}
		, REQ_USIM_SN = #{reqUsimSn}
		, RVISN_ID = #{SESSION_USER_ID}
		, RVISN_DTTM = SYSDATE 
WHERE 	REQUEST_KEY = #{requestKey}

/* rcpSelfSuffMapper.updateMcpReqStateUsim */
UPDATE	MCP_REQUEST_STATE@DL_MCP
SET		REQUEST_STATE_CODE = #{usimStateCode}

		, TB_CD = #{tbCd}

		, DLVRY_NO = #{dlvryNo}
		, RVISN_ID = #{SESSION_USER_ID}
		, RVISN_DTTM = SYSDATE 
WHERE REQUEST_KEY = #{requestKey}

/* rcpSelfSuffMapper.updateMcpReqStatePhone */
UPDATE	NMCP_REQUEST_APD_STATE@DL_MCP
SET		REQUEST_STATE_CODE = #{phoneStateCode}

		, TB_CD = #{phoneTbCd}

		, DLVRY_NO = #{phoneDlvryNo}
		, RVISN_ID = #{SESSION_USER_ID}
		, RVISN_DTTM = SYSDATE 
WHERE REQUEST_KEY = #{requestKey}

/* rcpSelfSuffMapper.updateMcpReqDlvry */
UPDATE	MCP_REQUEST_DLVRY@DL_MCP
SET		RVISN_ID = #{SESSION_USER_ID}
		, RVISN_DTTM = SYSDATE

		, DLVRY_NAME = #{dlvryName}


		, DLVRY_TEL_FN = #{dlvryTelFn}


		, DLVRY_TEL_MN = #{dlvryTelMn}


		, DLVRY_TEL_RN = #{dlvryTelRn}


		, DLVRY_MOBILE_FN = #{dlvryMobileFn}


		, DLVRY_MOBILE_MN = #{dlvryMobileMn}


		, DLVRY_MOBILE_RN = #{dlvryMobileRn}


		, DLVRY_POST = #{dlvryPost}


		, DLVRY_ADDR = #{dlvryAddr}


		, DLVRY_ADDR_DTL = #{dlvryAddrDtl}


		, DLVRY_MEMO = #{dlvryMemo}

WHERE REQUEST_KEY = #{requestKey}

/* rcpSelfSuffMapper.updateMcpReqApdDlvry */
UPDATE	NMCP_REQUEST_APD_DLVRY@DL_MCP
SET		RVISN_ID = #{SESSION_USER_ID}
		, RVISN_DTTM = SYSDATE

		, DLVRY_NAME = #{dlvryName}


		, DLVRY_TEL_FN = #{dlvryTelFn}


		, DLVRY_TEL_MN = #{dlvryTelMn}


		, DLVRY_TEL_RN = #{dlvryTelRn}


		, DLVRY_MOBILE_FN = #{dlvryMobileFn}


		, DLVRY_MOBILE_MN = #{dlvryMobileMn}


		, DLVRY_MOBILE_RN = #{dlvryMobileRn}


		, DLVRY_POST = #{dlvryPost}


		, DLVRY_ADDR = #{dlvryAddr}


		, DLVRY_ADDR_DTL = #{dlvryAddrDtl}


		, DLVRY_MEMO = #{dlvryMemo}

WHERE REQUEST_KEY = #{requestKey}

/* rcpSelfSuffMapper.updateMcpReqMask */
UPDATE	MCP_REQUEST@DL_MCP
SET		PSTATE = #{pstate}
		, RVISN_ID = #{SESSION_USER_ID}
		, RVISN_DTTM = SYSDATE 
WHERE 	REQUEST_KEY = #{requestKey}

/* rcpSelfSuffMapper.updateMcpApdReqMask */
UPDATE	NMCP_REQUEST_APD@DL_MCP
SET		PSTATE = #{pstate}
		, RVISN_ID = #{SESSION_USER_ID}
		, RVISN_DTTM = SYSDATE 
WHERE 	REQUEST_KEY = #{requestKey}

/* rcpSelfSuffMapper.updatePhoneDlvryNo */
UPDATE	NMCP_REQUEST_APD_STATE@DL_MCP
SET		TB_CD 					= #{tbCd, jdbcType=VARCHAR}
		, DLVRY_NO				= #{dlvryNo, jdbcType=VARCHAR}
		, REQUEST_STATE_CODE	= #{reqStateCd, jdbcType=VARCHAR} 
	   	, RVISN_ID  			= #{sessionUserId, jdbcType=VARCHAR}
		, RVISN_DTTM 			= SYSDATE 
WHERE	RES_NO 					= #{resNo, jdbcType=VARCHAR}

/* rcpSelfSuffMapper.updateUsimDlvryNo */
UPDATE	MCP_REQUEST_STATE@DL_MCP
SET		TB_CD 					= #{tbCd, jdbcType=VARCHAR}
		, DLVRY_NO				= #{dlvryNo, jdbcType=VARCHAR}
		, REQUEST_STATE_CODE	= #{reqStateCd, jdbcType=VARCHAR} 
	   	, RVISN_ID  			= #{sessionUserId, jdbcType=VARCHAR}
		, RVISN_DTTM 			= SYSDATE 
WHERE	RES_NO 					= #{resNo, jdbcType=VARCHAR}

/* rcpSelfSuffMapper.updateReqSrNo */
UPDATE  MCP_REQUEST@DL_MCP A
SET		RVISN_ID  		= #{sessionUserId, jdbcType=VARCHAR}
		, RVISN_DTTM 		=  SYSDATE

		, REQUEST_STATE_CODE 	= #{reqStateCd, jdbcType=VARCHAR}
		, REQ_USIM_SN 		= #{reqSrNo, jdbcType=VARCHAR}


		, REQ_PHONE_SN 		= #{reqSrNo, jdbcType=VARCHAR}

WHERE   RES_NO 				= #{resNo, jdbcType=VARCHAR}

/* rcpSelfSuffMapper.updateReqApdSrNo */
UPDATE  NMCP_REQUEST_APD@DL_MCP A
SET		RVISN_ID  		= #{sessionUserId, jdbcType=VARCHAR}
		, RVISN_DTTM 		=  SYSDATE

		, REQUEST_STATE_CODE 	= #{reqStateCd, jdbcType=VARCHAR}
		, REQ_USIM_SN 		= #{reqSrNo, jdbcType=VARCHAR}


		, REQ_PHONE_SN 		= #{reqSrNo, jdbcType=VARCHAR}

WHERE   RES_NO 				= #{resNo, jdbcType=VARCHAR}

